1	// ABOUTME: Chat panel UI module — rich markdown rendering of ACP agent conversations.
2	// ABOUTME: Manages chat tabs, WebSocket connections, streaming text, and tool call cards.
3	
4	(function () {
5	  "use strict";
6	
7	  // --- Markdown setup ---
8	  marked.setOptions({
9	    highlight: function (code, lang) {
10	      if (lang && hljs.getLanguage(lang)) {
11	        return hljs.highlight(code, { language: lang }).value;
12	      }
13	      return hljs.highlightAuto(code).value;
14	    },
15	    breaks: true,
16	    gfm: true,
17	  });
18	
19	  // --- State ---
20	  var chatTabs = {};
21	  var activeChatTabId = null;
22	  var chatTabIdCounter = 0;
23	
24	  // --- DOM refs ---
25	  var $chatPanel = document.getElementById("chat-panel");
26	  var $chatTabs = document.getElementById("chat-tabs");
27	  var $chatMessages = document.getElementById("chat-messages");
28	  var $chatInput = document.getElementById("chat-input");
29	  var $chatSend = document.getElementById("chat-send");
30	  var $chatStop = document.getElementById("chat-stop");
31	  var $chatClose = document.getElementById("chat-close");
32	  var $chatCost = document.getElementById("chat-cost");
33	  var $imagePreview = document.getElementById("chat-image-preview");
34	
35	
36	  // --- Helpers ---
37	
38	  function escapeHtml(s) {
39	    var div = document.createElement("div");
40	    div.textContent = s;
41	    return div.innerHTML;
42	  }
43	
44	  function renderMarkdown(text) {
45	    return DOMPurify.sanitize(marked.parse(text || ""));
46	  }
47	
48	  function generateChatTabId() {
49	    return "chat-" + (chatTabIdCounter++);
50	  }
51	
52	  function scrollToBottom() {
53	    if (!$chatMessages) return;
54	    $chatMessages.scrollTop = $chatMessages.scrollHeight;
55	  }
56	
57	  // --- Tool call icons by kind ---
58	  var TOOL_ICONS = {
59	    read: "&#128196;",     // page
60	    edit: "&#9998;",       // pencil
61	    execute: "&#9654;",    // play
62	    search: "&#128269;",   // magnifier
63	    "delete": "&#128465;", // trash
64	    think: "&#128161;",    // lightbulb
65	    fetch: "&#127760;",    // globe
66	  };
67	
68	  // --- Tab Management ---
69	
70	  function renderChatTabs() {
71	    $chatTabs.innerHTML = "";
72	    Object.keys(chatTabs).forEach(function (tabId) {
73	      var tab = chatTabs[tabId];
74	      var el = document.createElement("div");
75	      el.className = "chat-tab" + (tabId === activeChatTabId ? " active" : "");
76	      el.innerHTML =
77	        '<span class="chat-tab-title">' + escapeHtml(tab.title) + "</span>" +
78	        '<span class="chat-tab-close">&times;</span>';
79	
80	      el.querySelector(".chat-tab-title").addEventListener("click", function () {
81	        switchChatTab(tabId);
82	      });
83	      el.querySelector(".chat-tab-close").addEventListener("click", function (e) {
84	        e.stopPropagation();
85	        closeChatTab(tabId);
86	      });
87	      $chatTabs.appendChild(el);
88	    });
89	  }
90	
91	  function switchChatTab(tabId) {
92	    if (!chatTabs[tabId]) return;
93	    if (activeChatTabId && chatTabs[activeChatTabId]) {
94	      chatTabs[activeChatTabId].container.classList.remove("active");
95	    }
96	    activeChatTabId = tabId;
97	    chatTabs[tabId].container.classList.add("active");
98	    renderChatTabs();
99	    renderTurnSidebar(chatTabs[tabId]);
100	    updateInputState();
101	    renderImagePreview();
102	    scrollToBottom();
103	    $chatInput.focus();
104	  }
105	
106	  function closeChatTab(tabId) {
107	    var tab = chatTabs[tabId];
108	    if (!tab) return;
109	    var closedSessionId = tab.sessionId;
110	    if (tab.ws && tab.ws.readyState === WebSocket.OPEN) {
111	      tab.ws.close();
112	    }
113	    if (tab.container && tab.container.parentNode) {
114	      tab.container.parentNode.removeChild(tab.container);
115	    }
116	    delete chatTabs[tabId];
117	    if (closedSessionId) {
118	      emitSessionEvent("agent-session-closed", { sessionId: closedSessionId });
119	    }
120	
121	    var remaining = Object.keys(chatTabs);
122	    if (remaining.length > 0) {
123	      switchChatTab(remaining[remaining.length - 1]);
124	    } else {
125	      activeChatTabId = null;
126	      $chatPanel.classList.add("hidden");
127	      document.body.classList.remove("chat-open");
128	    }
129	    renderChatTabs();
130	  }
131	
132	  // --- Chat Tab Creation ---
133	
134	  function createChatTab(title, agent, cwd, existingSessionId, sessionSummary) {
135	    var tabId = generateChatTabId();
136	
137	    var container = document.createElement("div");
138	    container.className = "chat-tab-container";
139	    $chatMessages.appendChild(container);
140	
141	    var tabData = {
142	      id: tabId,
143	      ws: null,
144	      sessionId: null,
145	      agent: agent,
146	      cwd: cwd,
147	      container: container,
148	      title: title,
149	      streaming: false,
150	      messageQueue: [],
151	      currentTextAccum: "",
152	      currentTextEl: null,
153	      thinkingAccum: "",
154	      thinkingEl: null,
155	      renderScheduled: false,
156	      sessionSummary: sessionSummary || null,
157	      userTurns: [],
158	      activeTurnIndex: -1,
159	      pendingImages: [],
160	    };
161	    chatTabs[tabId] = tabData;
162	
163	    // Show panel
164	    $chatPanel.classList.remove("hidden");
165	    document.body.classList.add("chat-open");
166	
167	    // Hide previous active tab
168	    if (activeChatTabId && chatTabs[activeChatTabId]) {
169	      chatTabs[activeChatTabId].container.classList.remove("active");
170	    }
171	    activeChatTabId = tabId;
172	    container.classList.add("active");
173	
174	    renderChatTabs();
175	    renderTurnSidebar(tabData);
176	    updateInputState();
177	    renderImagePreview();
178	    connectWebSocket(tabData, existingSessionId);
179	    $chatInput.focus();
180	
181	    return tabId;
182	  }
183	
184	  // --- WebSocket ---
185	
186	  function connectWebSocket(tabData, sessionId) {
187	    var wsProtocol = location.protocol === "https:" ? "wss:" : "ws:";
188	    var wsUrl = wsProtocol + "//" + location.host + "/ws/chat";
189	    var ws = new WebSocket(wsUrl);
190	    tabData.ws = ws;
191	
192	    ws.onopen = function () {
193	      ws.send(JSON.stringify({
194	        type: "start",
195	        agent: tabData.agent,
196	        cwd: tabData.cwd,
197	        sessionId: sessionId || undefined,
198	      }));
199	    };
200	
201	    ws.onmessage = function (evt) {
202	      try {
203	        var msg = JSON.parse(evt.data);
204	        handleServerMessage(tabData, msg);
205	      } catch (e) {
206	        console.error("Failed to parse chat message:", e);
207	      }
208	    };
209	
210	    ws.onclose = function () {
211	      tabData.streaming = false;
212	      updateInputState();
213	    };
214	
215	    ws.onerror = function () {
216	      appendSystemMessage(tabData, "Connection error");
217	    };
218	  }
219	
220	  // --- Message Routing ---
221	
222	  function handleServerMessage(tabData, msg) {
223	    switch (msg.type) {
224	      case "session_init":
225	        tabData.sessionId = msg.sessionId;
226	        if (msg.agentInfo) {
227	          appendSystemMessage(tabData, msg.agentInfo.title + " connected");
228	        }
229	        if (!msg.historyLoaded && tabData.sessionSummary) {
230	          appendInfoBanner(tabData, "Previous messages not available. " + tabData.sessionSummary);
231	        }
232	        emitSessionEvent("agent-session-started", {
233	          sessionId: msg.sessionId,
234	          agent: tabData.agent,
235	          cwd: tabData.cwd,
236	          title: tabData.title,
237	        });
238	        break;
239	
240	      case "update":
241	        handleUpdate(tabData, msg);
242	        break;
243	
244	      case "turn_complete":
245	        finalizeAssistantMessage(tabData);
246	        collapseCompletedTools(tabData);
247	        tabData.streaming = false;
248	        flushMessageQueue(tabData);
249	        updateInputState();
250	        emitSessionEvent("agent-session-updated", {
251	          sessionId: tabData.sessionId,
252	          streaming: tabData.streaming,
253	        });
254	        break;
255	
256	      case "error":
257	        appendSystemMessage(tabData, "Error: " + (msg.message || "Unknown error"));
258	        tabData.streaming = false;
259	        updateInputState();
260	        break;
261	
262	      case "auth_required":
263	        appendAuthBanner(tabData, msg);
264	        break;
265	
266	      case "session_terminated":
267	        tabData.streaming = false;
268	        tabData.terminated = true;
269	        appendSessionTerminated(tabData);
270	        updateInputState();
271	        break;
272	
273	      case "session_restarted":
274	        tabData.terminated = false;
275	        tabData.sessionId = msg.sessionId || tabData.sessionId;
276	        appendSystemMessage(tabData, "Session resumed");
277	        break;
278	
279	      default:
280	        console.log("Unknown chat message type:", msg.type);
281	    }
282	  }
283	
284	  function handleUpdate(tabData, msg) {
285	    var su = msg.sessionUpdate;
286	    switch (su) {
287	      case "agent_message_chunk":
288	        var text = (msg.content && msg.content.text) || "";
289	        if (text) appendAgentText(tabData, text);
290	        break;
291	
292	      case "agent_thought_chunk":
293	        var thought = (msg.content && msg.content.text) || "";
294	        if (thought) appendThinking(tabData, thought);
295	        break;
296	
297	      case "user_message_chunk":
298	        var userText = (msg.content && msg.content.text) || "";
299	        if (userText) appendUserBubble(tabData, userText);
300	        break;
301	
302	      case "tool_call":
303	        renderToolCall(tabData, msg);
304	        break;
305	
306	      case "tool_call_update":
307	        updateToolCall(tabData, msg);
308	        break;
309	
310	      case "usage_update":
311	        renderUsage(msg);
312	        break;
313	
314	      case "plan":
315	        renderPlan(tabData, msg.entries || []);
316	        break;
317	
318	      default:
319	        // Gracefully ignore unknown update types
320	        break;
321	    }
322	  }
323	
324	  // --- Rendering: User Messages ---
325	
326	  function appendUserBubble(tabData, text, images) {
327	    // Close any open agent message
328	    finalizeAssistantMessage(tabData);
329	
330	    var turnIndex = tabData.userTurns.length;
331	    var bubble = document.createElement("div");
332	    bubble.className = "chat-bubble user";
333	    bubble.setAttribute("data-turn-index", turnIndex);
334	    if (images && images.length) {
335	      var imgStrip = document.createElement("div");
336	      imgStrip.className = "chat-bubble-images";
337	      images.forEach(function (img) {
338	        var el = document.createElement("img");
339	        el.src = "data:" + img.mimeType + ";base64," + img.data;
340	        el.className = "chat-bubble-img";
341	        imgStrip.appendChild(el);
342	      });
343	      bubble.appendChild(imgStrip);
344	    }
345	    if (text) {
346	      var textEl = document.createElement("span");
347	      textEl.textContent = text;
348	      bubble.appendChild(textEl);
349	    }
350	    tabData.container.appendChild(bubble);
351	
352	    tabData.userTurns.push({ index: turnIndex, element: bubble, text: text || "(image)" });
353	    renderTurnSidebar(tabData);
354	    scrollToBottom();
355	  }
356	
357	  // --- Rendering: Agent Text (streaming) ---
358	
359	  function appendAgentText(tabData, text) {
360	    // Close thinking if open
361	    finalizeThinking(tabData);
362	
363	    tabData.currentTextAccum += text;
364	    if (!tabData.currentTextEl) {
365	      var bubble = document.createElement("div");
366	      bubble.className = "chat-bubble assistant";
367	      var content = document.createElement("div");
368	      content.className = "chat-md-content";
369	      bubble.appendChild(content);
370	      tabData.container.appendChild(bubble);
371	      tabData.currentTextEl = content;
372	    }
373	    scheduleRender(tabData);
374	  }
375	
376	  function scheduleRender(tabData) {
377	    if (tabData.renderScheduled) return;
378	    tabData.renderScheduled = true;
379	    requestAnimationFrame(function () {
380	      tabData.renderScheduled = false;
381	      if (tabData.currentTextEl) {
382	        tabData.currentTextEl.innerHTML = renderMarkdown(tabData.currentTextAccum);
383	      }
384	      scrollToBottom();
385	    });
386	  }
387	
388	  function finalizeAssistantMessage(tabData) {
389	    if (tabData.currentTextEl && tabData.currentTextAccum) {
390	      tabData.currentTextEl.innerHTML = renderMarkdown(tabData.currentTextAccum);
391	    }
392	    tabData.currentTextEl = null;
393	    tabData.currentTextAccum = "";
394	    finalizeThinking(tabData);
395	  }
396	
397	  // --- Rendering: Thinking ---
398	
399	  function appendThinking(tabData, text) {
400	    tabData.thinkingAccum += text;
401	    if (!tabData.thinkingEl) {
402	      var block = document.createElement("details");
403	      block.className = "chat-thinking";
404	      block.innerHTML = "<summary>Thinking...</summary><div class='chat-thinking-content'></div>";
405	      tabData.container.appendChild(block);
406	      tabData.thinkingEl = block.querySelector(".chat-thinking-content");
407	    }
408	    tabData.thinkingEl.textContent = tabData.thinkingAccum;
409	    scrollToBottom();
410	  }
411	
412	  function finalizeThinking(tabData) {
413	    tabData.thinkingEl = null;
414	    tabData.thinkingAccum = "";
415	  }
416	
417	  // --- Rendering: Tool Calls ---
418	
419	  function renderToolCall(tabData, tc) {
420	    // Close any open text/thinking so the tool card appears between bubbles
421	    finalizeAssistantMessage(tabData);
422	
423	    var card = document.createElement("details");
424	    card.className = "chat-tool-card";
425	    card.setAttribute("data-tool-id", tc.toolCallId || "");
426	
427	    var status = tc.status || "pending";
428	    var kind = tc.kind || "other";
429	    var icon = TOOL_ICONS[kind] || "&#128295;"; // wrench default
430	    var title = tc.title || "Tool call";
431	    var locationText = "";
432	    if (tc.locations && tc.locations.length > 0) {
433	      var loc = tc.locations[0];
434	      var path = (loc && loc.path) || "";
435	      locationText = '<span class="chat-tool-path">' + escapeHtml(path.split("/").pop()) + "</span>";
436	    }
437	
438	    card.innerHTML =
439	      '<summary class="chat-tool-header">' +
440	        '<span class="chat-tool-icon">' + icon + "</span>" +
441	        '<span class="chat-tool-title">' + escapeHtml(title) + "</span>" +
442	        locationText +
443	        '<span class="chat-tool-status ' + escapeHtml(status) + '">' + escapeHtml(status) + "</span>" +
444	      "</summary>" +
445	      '<div class="chat-tool-body"></div>';
446	
447	    tabData.container.appendChild(card);
448	    scrollToBottom();
449	  }
450	
451	  function updateToolCall(tabData, update) {
452	    var card = tabData.container.querySelector(
453	      '.chat-tool-card[data-tool-id="' + (update.toolCallId || "") + '"]'
454	    );
455	    if (!card) return;
456	
457	    // Update status badge
458	    if (update.status) {
459	      var badge = card.querySelector(".chat-tool-status");
460	      if (badge) {
461	        badge.textContent = update.status;
462	        badge.className = "chat-tool-status " + update.status;
463	      }
464	    }
465	
466	    // Append content
467	    if (update.content && update.content.length > 0) {
468	      var body = card.querySelector(".chat-tool-body");
469	      if (body) {
470	        update.content.forEach(function (item) {
471	          if (item.type === "diff") {
472	            renderDiff(body, item);
473	          } else if (item.type === "content" && item.content) {
474	            var text = item.content.text || "";
475	            if (text) {
476	              var pre = document.createElement("pre");
477	              pre.className = "chat-tool-output";
478	              pre.textContent = text.length > 2000 ? text.substring(0, 2000) + "\n...(truncated)" : text;
479	              body.appendChild(pre);
480	            }
481	          }
482	        });
483	      }
484	    }
485	    scrollToBottom();
486	  }
487	
488	  function renderDiff(container, diff) {
489	    var el = document.createElement("div");
490	    el.className = "chat-diff";
491	    var header = document.createElement("div");
492	    header.className = "chat-diff-header";
493	    header.textContent = diff.path || "file";
494	    el.appendChild(header);
495	
496	    var pre = document.createElement("pre");
497	    pre.className = "chat-diff-content";
498	    // Simple diff display: show newText (the result)
499	    pre.textContent = diff.newText || "";
500	    el.appendChild(pre);
501	    container.appendChild(el);
502	  }
503	
504	  // --- Rendering: Plan ---
505	
506	  function renderPlan(tabData, entries) {
507	    // Remove any existing plan
508	    var existing = tabData.container.querySelector(".chat-plan");
509	    if (existing) existing.parentNode.removeChild(existing);
510	
511	    if (!entries.length) return;
512	
513	    var el = document.createElement("div");
514	    el.className = "chat-plan";
515	    el.innerHTML = "<div class='chat-plan-title'>Plan</div>";
516	    var list = document.createElement("ul");
517	    entries.forEach(function (entry) {
518	      var li = document.createElement("li");
519	      var statusIcon = entry.status === "completed" ? "&#10003;" : entry.status === "failed" ? "&#10007;" : "&#9744;";
520	      li.innerHTML = '<span class="chat-plan-icon">' + statusIcon + '</span> ' + escapeHtml(entry.content || "");
521	      li.className = "chat-plan-entry " + (entry.status || "pending");
522	      list.appendChild(li);
523	    });
524	    el.appendChild(list);
525	    tabData.container.appendChild(el);
526	    scrollToBottom();
527	  }
528	
529	  // --- Rendering: Usage ---
530	
531	  function renderUsage(msg) {
532	    if (!$chatCost) return;
533	    var parts = [];
534	
535	    if (msg.cost && msg.cost.amount != null) {
536	      parts.push("$" + msg.cost.amount.toFixed(4));
537	    }
538	
539	    if (msg.used != null && msg.size != null && msg.size > 0) {
540	      var usedK = Math.round(msg.used / 1000);
541	      var sizeK = Math.round(msg.size / 1000);
542	      var pct = Math.round((msg.used / msg.size) * 100);
543	      parts.push(usedK + "K / " + sizeK + "K (" + pct + "%)");
544	    }
545	
546	    if (parts.length > 0) {
547	      $chatCost.textContent = parts.join(" | ");
548	      $chatCost.classList.remove("hidden", "context-warn", "context-critical");
549	      if (msg.used != null && msg.size != null && msg.size > 0) {
550	        var pct = (msg.used / msg.size) * 100;
551	        if (pct >= 90) {
552	          $chatCost.classList.add("context-critical");
553	        } else if (pct >= 75) {
554	          $chatCost.classList.add("context-warn");
555	        }
556	      }
557	    }
558	  }
559	
560	  // --- Turn Navigation Sidebar ---
561	
562	  var $turnSidebar = document.getElementById("chat-turn-sidebar");
563	
564	  function renderTurnSidebar(tabData) {
565	    if (!$turnSidebar) return;
566	    var list = $turnSidebar.querySelector(".turn-list");
567	    if (list) list.innerHTML = "";
568	    var turns = tabData.userTurns;
569	    if (turns.length === 0) {
570	      $turnSidebar.classList.add("hidden");
571	      return;
572	    }
573	
574	    $turnSidebar.classList.remove("hidden");
575	    if (!list) return;
576	
577	    turns.forEach(function (turn) {
578	      var item = document.createElement("div");
579	      item.className = "turn-item" + (turn.index === tabData.activeTurnIndex ? " active" : "");
580	      item.setAttribute("data-turn-index", turn.index);
581	
582	      var label = document.createElement("span");
583	      label.className = "turn-label";
584	      label.textContent = (turn.index + 1);
585	
586	      var preview = document.createElement("span");
587	      preview.className = "turn-preview";
588	      var previewText = turn.text.length > 60 ? turn.text.substring(0, 60) + "..." : turn.text;
589	      preview.textContent = previewText;
590	
591	      item.appendChild(label);
592	      item.appendChild(preview);
593	      item.addEventListener("click", function () {
594	        jumpToTurn(tabData, turn.index);
595	      });
596	      list.appendChild(item);
597	    });
598	
599	    // Update counter
600	    var counter = $turnSidebar.querySelector(".turn-counter");
601	    if (counter) {
602	      var current = tabData.activeTurnIndex >= 0 ? (tabData.activeTurnIndex + 1) : "-";
603	      counter.textContent = current + " / " + turns.length;
604	    }
605	  }
606	
607	  function jumpToTurn(tabData, turnIndex) {
608	    var turns = tabData.userTurns;
609	    if (turnIndex < 0 || turnIndex >= turns.length) return;
610	
611	    tabData.activeTurnIndex = turnIndex;
612	    var el = turns[turnIndex].element;
613	    el.scrollIntoView({ behavior: "smooth", block: "center" });
614	
615	    // Brief highlight flash
616	    el.classList.add("turn-highlight");
617	    setTimeout(function () { el.classList.remove("turn-highlight"); }, 1500);
618	
619	    renderTurnSidebar(tabData);
620	  }
621	
622	  function jumpToPreviousTurn(tabData) {
623	    if (!tabData || tabData.userTurns.length === 0) return;
624	    var next = tabData.activeTurnIndex <= 0 ? 0 : tabData.activeTurnIndex - 1;
625	    jumpToTurn(tabData, next);
626	  }
627	
628	  function jumpToNextTurn(tabData) {
629	    if (!tabData || tabData.userTurns.length === 0) return;
630	    var max = tabData.userTurns.length - 1;
631	    var next = tabData.activeTurnIndex >= max ? max : tabData.activeTurnIndex + 1;
632	    jumpToTurn(tabData, next);
633	  }
634	
635	  // Toggle sidebar visibility
636	  function toggleTurnSidebar() {
637	    if (!$turnSidebar) return;
638	    $turnSidebar.classList.toggle("collapsed");
639	  }
640	
641	  // --- Tool Collapsing ---
642	
643	  function collapseCompletedTools(tabData) {
644	    var container = tabData.container;
645	    var children = Array.from(container.children);
646	    var i = 0;
647	
648	    while (i < children.length) {
649	      // Find runs of consecutive completed tool cards
650	      if (isCompletedToolCard(children[i])) {
651	        var runStart = i;
652	        while (i < children.length && isCompletedToolCard(children[i])) {
653	          i++;
654	        }
655	        var runLength = i - runStart;
656	        if (runLength >= 3) {
657	          var details = container.ownerDocument.createElement("details");
658	          details.className = "chat-tool-group";
659	          var summary = container.ownerDocument.createElement("summary");
660	          summary.textContent = runLength + " tool calls completed";
661	          details.appendChild(summary);
662	
663	          // Insert the details element before the first card in the run
664	          container.insertBefore(details, children[runStart]);
665	          for (var j = runStart; j < runStart + runLength; j++) {
666	            details.appendChild(children[j]);
667	          }
668	        }
669	      } else {
670	        i++;
671	      }
672	    }
673	  }
674	
675	  function isCompletedToolCard(el) {
676	    if (!el || !el.classList || !el.classList.contains("chat-tool-card")) return false;
677	    var statusEl = el.querySelector(".chat-tool-status");
678	    return statusEl && statusEl.classList.contains("completed");
679	  }
680	
681	  // --- Rendering: System / Info / Auth ---
682	
683	  function appendSystemMessage(tabData, text) {
684	    var el = document.createElement("div");
685	    el.className = "chat-system-msg";
686	    el.textContent = text;
687	    tabData.container.appendChild(el);
688	    scrollToBottom();
689	  }
690	
691	  function appendInfoBanner(tabData, text) {
692	    var el = document.createElement("div");
693	    el.className = "chat-info-banner";
694	    el.textContent = text;
695	    tabData.container.appendChild(el);
696	    scrollToBottom();
697	  }
698	
699	  function appendSessionTerminated(tabData) {
700	    var el = document.createElement("div");
701	    el.className = "chat-system-msg chat-terminated";
702	    el.textContent = "Session ended — send a message to resume";
703	    tabData.container.appendChild(el);
704	    scrollToBottom();
705	  }
706	
707	  function appendAuthBanner(tabData, msg) {
708	    var el = document.createElement("div");
709	    el.className = "chat-auth-banner";
710	    el.innerHTML =
711	      '<div class="chat-auth-text">' + escapeHtml(msg.message || "Authentication required") + "</div>" +
712	      '<button class="chat-auth-retry">Retry</button>';
713	    el.querySelector(".chat-auth-retry").addEventListener("click", function () {
714	      if (tabData.ws && tabData.ws.readyState === WebSocket.OPEN) {
715	        tabData.ws.send(JSON.stringify({ type: "retry" }));
716	        el.parentNode.removeChild(el);
717	      }
718	    });
719	    tabData.container.appendChild(el);
720	    scrollToBottom();
721	  }
722	
723	  // --- Input Handling ---
724	
725	  function sendUserMessage() {
726	    if (!activeChatTabId || !chatTabs[activeChatTabId]) return;
727	    var tab = chatTabs[activeChatTabId];
728	
729	    var text = $chatInput.value.trim();
730	    var images = tab.pendingImages.slice();
731	    if (!text && !images.length) return;
732	    $chatInput.value = "";
733	    $chatInput.style.height = "auto";
734	
735	    appendUserBubble(tab, text, images);
736	    tab.pendingImages = [];
737	    renderImagePreview();
738	    updateInputPlaceholder();
739	
740	    var queuedMsg = { type: "user_message", text: text };
741	    if (images.length) {
742	      queuedMsg.images = images.map(function (img) {
743	        return { data: img.data, mimeType: img.mimeType };
744	      });
745	    }
746	
747	    if (tab.streaming) {
748	      if (!tab.messageQueue) tab.messageQueue = [];
749	      tab.messageQueue.push(queuedMsg);
750	      updateInputState();
751	      return;
752	    }
753	
754	    sendToAgent(tab, queuedMsg);
755	  }
756	
757	  function sendToAgent(tab, msg) {
758	    if (tab.ws && tab.ws.readyState === WebSocket.OPEN) {
759	      tab.ws.send(JSON.stringify(msg));
760	      tab.streaming = true;
761	      updateInputState();
762	      emitSessionEvent("agent-session-updated", {
763	        sessionId: tab.sessionId,
764	        streaming: true,
765	      });
766	    }
767	  }
768	
769	  function flushMessageQueue(tab) {
770	    if (!tab.messageQueue || tab.messageQueue.length === 0) return;
771	    var next = tab.messageQueue.shift();
772	    sendToAgent(tab, next);
773	  }
774	
775	  function cancelAgent() {
776	    if (!activeChatTabId || !chatTabs[activeChatTabId]) return;
777	    var tab = chatTabs[activeChatTabId];
778	    if (!tab.streaming) return;
779	    if (tab.ws && tab.ws.readyState === WebSocket.OPEN) {
780	      tab.ws.send(JSON.stringify({ type: "cancel" }));
781	    }
782	    tab.messageQueue = [];
783	    tab.streaming = false;
784	    appendSystemMessage(tab, "Cancelled by user");
785	    finalizeAssistantMessage(tab);
786	    updateInputState();
787	  }
788	
789	  function updateInputState() {
790	    var tab = activeChatTabId ? chatTabs[activeChatTabId] : null;
791	    var streaming = tab && tab.streaming;
792	    var queued = tab && tab.messageQueue && tab.messageQueue.length > 0;
793	    $chatInput.disabled = false;
794	    // Show stop button during streaming, send button otherwise
795	    if (streaming) {
796	      $chatSend.classList.add("hidden");
797	      $chatStop.classList.remove("hidden");
798	    } else {
799	      $chatSend.classList.remove("hidden");
800	      $chatStop.classList.add("hidden");
801	    }
802	    if (streaming && queued) {
803	      $chatInput.placeholder = queued + " queued...";
804	    } else if (streaming) {
805	      $chatInput.placeholder = "Agent working... Esc to stop";
806	    } else if (tab && tab.terminated) {
807	      $chatInput.placeholder = "Send a message to resume session...";
808	    } else {
809	      $chatInput.placeholder = "Send a message...";
810	    }
811	  }
812	
813	  // Auto-grow textarea
814	  $chatInput.addEventListener("input", function () {
815	    this.style.height = "auto";
816	    this.style.height = Math.min(this.scrollHeight, 150) + "px";
817	  });
818	
819	  // Enter to send, Shift+Enter for newline, Esc to stop
820	  $chatInput.addEventListener("keydown", function (e) {
821	    if (e.key === "Enter" && !e.shiftKey) {
822	      e.preventDefault();
823	      sendUserMessage();
824	    } else if (e.key === "Escape") {
825	      var tab = activeChatTabId ? chatTabs[activeChatTabId] : null;
826	      if (tab && tab.streaming) {
827	        e.preventDefault();
828	        cancelAgent();
829	      }
830	    }
831	  });
832	
833	  $chatStop.addEventListener("click", cancelAgent);
834	
835	  $chatSend.addEventListener("click", sendUserMessage);
836	
837	  // --- Image Paste ---
838	
839	  $chatInput.addEventListener("paste", function (e) {
840	    var tab = activeChatTabId ? chatTabs[activeChatTabId] : null;
841	    if (!tab || tab.streaming) return;
842	
843	    var items = e.clipboardData && e.clipboardData.items;
844	    if (!items) return;
845	
846	    for (var i = 0; i < items.length; i++) {
847	      if (items[i].type.indexOf("image/") === 0) {
848	        e.preventDefault();
849	        var file = items[i].getAsFile();
850	        if (!file) continue;
851	        readImageFile(tab, file);
852	      }
853	    }
854	  });
855	
856	  function readImageFile(tab, file) {
857	    var reader = new FileReader();
858	    reader.onload = function () {
859	      // result is "data:<mimeType>;base64,<data>"
860	      var parts = reader.result.split(",");
861	      var mimeType = file.type || "image/png";
862	      var data = parts[1];
863	      tab.pendingImages.push({ data: data, mimeType: mimeType });
864	      renderImagePreview();
865	      updateInputPlaceholder();
866	    };
867	    reader.readAsDataURL(file);
868	  }
869	
870	  function updateInputPlaceholder() {
871	    var tab = activeChatTabId ? chatTabs[activeChatTabId] : null;
872	    if (!tab || tab.streaming || tab.terminated) return;
873	    var n = tab.pendingImages.length;
874	    if (n > 0) {
875	      $chatInput.placeholder = n + " image" + (n > 1 ? "s" : "") + " attached — add text or press Enter to send";
876	    } else {
877	      $chatInput.placeholder = "Send a message...";
878	    }
879	  }
880	
881	  function renderImagePreview() {
882	    var tab = activeChatTabId ? chatTabs[activeChatTabId] : null;
883	    $imagePreview.innerHTML = "";
884	    if (!tab || !tab.pendingImages.length) {
885	      $imagePreview.classList.remove("active");
886	      return;
887	    }
888	    $imagePreview.classList.add("active");
889	    tab.pendingImages.forEach(function (img, idx) {
890	      var thumb = document.createElement("div");
891	      thumb.className = "image-preview-thumb";
892	      var imgEl = document.createElement("img");
893	      imgEl.src = "data:" + img.mimeType + ";base64," + img.data;
894	      thumb.appendChild(imgEl);
895	      var removeBtn = document.createElement("button");
896	      removeBtn.className = "image-preview-remove";
897	      removeBtn.textContent = "\u00d7";
898	      removeBtn.setAttribute("data-idx", idx);
899	      removeBtn.addEventListener("click", function () {
900	        tab.pendingImages.splice(idx, 1);
901	        renderImagePreview();
902	        updateInputPlaceholder();
903	      });
904	      thumb.appendChild(removeBtn);
905	      $imagePreview.appendChild(thumb);
906	    });
907	  }
908	
909	
910	  // Turn navigation keyboard shortcuts (Ctrl+Up/Down)
911	  document.addEventListener("keydown", function (e) {
912	    if (!activeChatTabId || !chatTabs[activeChatTabId]) return;
913	    var tab = chatTabs[activeChatTabId];
914	    if (!$chatPanel || $chatPanel.classList.contains("hidden")) return;
915	
916	    if (e.ctrlKey && e.key === "ArrowUp") {
917	      e.preventDefault();
918	      jumpToPreviousTurn(tab);
919	    } else if (e.ctrlKey && e.key === "ArrowDown") {
920	      e.preventDefault();
921	      jumpToNextTurn(tab);
922	    } else if (e.ctrlKey && e.key === "t") {
923	      e.preventDefault();
924	      toggleTurnSidebar();
925	    }
926	  });
927	
928	  $chatClose.addEventListener("click", function () {
929	    // Close all tabs
930	    Object.keys(chatTabs).forEach(function (tabId) {
931	      var tab = chatTabs[tabId];
932	      if (tab.ws && tab.ws.readyState === WebSocket.OPEN) tab.ws.close();
933	      if (tab.container && tab.container.parentNode) tab.container.parentNode.removeChild(tab.container);
934	    });
935	    chatTabs = {};
936	    activeChatTabId = null;
937	    $chatPanel.classList.add("hidden");
938	    if ($turnSidebar) $turnSidebar.classList.add("hidden");
939	    document.body.classList.remove("chat-open");
940	    renderChatTabs();
941	  });
942	
943	
944	  // --- Public API (called from app.js) ---
945	
946	  // --- Custom Events for dashboard integration ---
947	
948	  function emitSessionEvent(eventName, detail) {
949	    window.dispatchEvent(new CustomEvent(eventName, { detail: detail }));
950	  }
951	
952	  window.AgentChat = {
953	    // Returns set of sessionIds that have open chat tabs
954	    getActiveSessionIds: function () {
955	      var ids = new Set();
956	      Object.keys(chatTabs).forEach(function (tabId) {
957	        var tab = chatTabs[tabId];
