.chat-panel {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  height: 50vh;
  background: var(--bg-primary, #111111);
  border-top: 3px solid var(--accent, #FF4D00);
  display: flex;
  flex-direction: column;
  z-index: 100;
}

.chat-panel.hidden {
  display: none;
}

.chat-panel-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 8px 0 0;
  background: var(--bg-secondary, #1a1a1a);
  border-bottom: 1px solid var(--border, #333);
  flex-shrink: 0;
}

.chat-tabs {
  display: flex;
  flex: 1;
  overflow-x: auto;
  scrollbar-width: none;
  gap: 1px;
}

.chat-tabs::-webkit-scrollbar { display: none; }

.chat-tab {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 8px 14px;
  font-family: var(--font-mono, monospace);
  font-size: 12px;
  color: var(--text-muted);
  cursor: pointer;
  white-space: nowrap;
  max-width: 200px;
  overflow: hidden;
  text-overflow: ellipsis;
  border-bottom: 2px solid transparent;
  transition: all 0.15s;
  flex-shrink: 0;
}

.chat-tab:hover { color: var(--text-secondary); }
.chat-tab.active {
  color: var(--text-primary);
  background: var(--bg-surface);
  font-weight: 600;
  border-bottom: 3px solid var(--accent, #FF4D00);
}

.chat-tab-close {
  font-size: 14px;
  opacity: 0.4;
  cursor: pointer;
}
.chat-tab-close:hover { opacity: 1; }

.chat-panel-controls {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-shrink: 0;
}

.chat-cost {
  font-family: var(--font-mono, monospace);
  font-size: 11px;
  color: var(--text-muted);
  padding: 2px 8px;
  border: 1px solid var(--border);
  border-radius: 3px;
  white-space: nowrap;
}
.chat-cost.context-warn {
  color: #e5c07b;
  border-color: #e5c07b44;
}
.chat-cost.context-critical {
  color: #e06c75;
  border-color: #e06c7544;
}


.chat-panel-close {
  font-size: 18px;
  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  padding: 4px 8px;
}
.chat-panel-close:hover { color: var(--text-primary); }

/* Chat body: sidebar + messages side by side */
.chat-body {
  display: flex;
  flex: 1;
  overflow: hidden;
  min-height: 0;
}

/* Turn navigation sidebar */
.chat-turn-sidebar {
  width: 220px;
  flex-shrink: 0;
  border-right: 1px solid var(--border, #333);
  background: var(--bg-secondary, #1a1a1a);

