17	/**
18	 * Create a jsdom environment with the minimal DOM and globals that chat.js needs,
19	 * load chat.js, and return the window object for testing.
20	 */
21	function createChatEnv() {
22	  const html = `<!DOCTYPE html><html><body>
23	    <div id="chat-panel" class="chat-panel hidden">
24	      <div class="chat-panel-header">
25	        <div class="chat-tabs" id="chat-tabs"></div>
26	        <div class="chat-panel-controls">
27	          <span class="chat-cost hidden" id="chat-cost"></span>
28	          <button class="chat-panel-close" id="chat-close">&times;</button>
29	        </div>
30	      </div>
31	      <div class="chat-body">
32	        <div class="chat-turn-sidebar hidden" id="chat-turn-sidebar">
33	          <div class="turn-sidebar-header">
34	            <span class="turn-sidebar-title">Turns</span>
35	            <span class="turn-counter">-</span>
36	          </div>
37	          <div class="turn-list"></div>
38	        </div>
39	        <div class="chat-messages" id="chat-messages"></div>
40	      </div>
41	      <div class="chat-image-preview" id="chat-image-preview"></div>
42	      <div class="chat-input-bar">
43	        <textarea id="chat-input" class="chat-input" rows="1"></textarea>
44	        <button id="chat-send" class="chat-send-btn">&uarr;</button>
45	        <button id="chat-stop" class="chat-stop-btn hidden">&square;</button>
46	      </div>
47	    </div>
48	  </body></html>`;
49	
50	  const dom = new JSDOM(html, {
51	    url: "http://localhost:8100",
52	    runScripts: "dangerously",
53	    pretendToBeVisual: true,
54	  });
55	  const { window } = dom;
56	
57	  // Stub marked (returns text wrapped in <p>)
58	  window.marked = {
59	    parse: (text) => "<p>" + (text || "").replace(/\n\n/g, "</p><p>") + "</p>",
60	    setOptions: () => {},
61	  };
62	
63	  // Stub DOMPurify (pass-through)
64	  window.DOMPurify = { sanitize: (html) => html };
65	
66	  // Stub hljs
67	  window.hljs = { getLanguage: () => false, highlightAuto: (c) => ({ value: c }) };
68	
69	  // Stub requestAnimationFrame (execute synchronously)
70	  window.requestAnimationFrame = (fn) => fn();
71	
72	  // Load chat.js
73	  window.eval(CHAT_JS);
74	
75	  return window;
76	}
