78	/**
79	 * Helper: create a tabData object attached to a container div.
80	 */
81	function makeTab(window) {
82	  const container = window.document.createElement("div");
83	  container.className = "chat-tab-container active";
84	  window.document.getElementById("chat-messages").appendChild(container);
85	  return window._chatInternals.createTabData(container);
86	}
