    api.renderToolCall(tab, { toolCallId: "tc-2", title: "Edit", status: "completed" });
    api.renderToolCall(tab, { toolCallId: "tc-3", title: "Bash", status: "in_progress" });

    api.collapseCompletedTools(tab);

