// ABOUTME: Dashboard client — fetches session data, renders UI, handles interactions.
// ABOUTME: Vanilla JS with no build step; polls /api/sessions for updates.

(function () {
  "use strict";

  // --- Theme ---
  // Cycles: auto → dark → light → auto. Persisted in localStorage.
  // JS manages the .dark class on <html> based on effective theme.

  var THEME_CYCLE = ["auto", "dark", "light"];
  var THEME_LABELS = { auto: "Auto", dark: "Dark", light: "Light" };
  var $themeToggle = document.getElementById("theme-toggle");
  var darkMediaQuery = window.matchMedia("(prefers-color-scheme: dark)");

  function getStoredTheme() {
    return localStorage.getItem("ak-theme") || "auto";
  }

  function applyTheme(theme) {
    var isDark = theme === "dark" || (theme === "auto" && darkMediaQuery.matches);
    document.documentElement.classList.toggle("dark", isDark);
    $themeToggle.textContent = THEME_LABELS[theme];
  }

  function cycleTheme() {
    var current = getStoredTheme();
    var next = THEME_CYCLE[(THEME_CYCLE.indexOf(current) + 1) % THEME_CYCLE.length];
    localStorage.setItem("ak-theme", next);
    applyTheme(next);
  }

  // Apply on load
  applyTheme(getStoredTheme());

  // React to OS theme changes (only matters in auto mode)
  darkMediaQuery.addEventListener("change", function () {
    if (getStoredTheme() === "auto") applyTheme("auto");
  });

  $themeToggle.addEventListener("click", cycleTheme);

  // --- State ---
  let dashboardData = null;
  let lastScannedTime = null;
  let expandedRepos = new Set(); // repo_root values that are expanded
  var timeFilterDays = Infinity; // max days back to show (Infinity = all)
  var availableAgents = ["claude"]; // fetched from /api/agents on load

  // --- DOM refs ---
  const $loading = document.getElementById("loading");
  const $repoGroups = document.getElementById("repo-groups");
  const $nonRepoGroups = document.getElementById("non-repo-groups");
  const $chronoView = document.getElementById("chrono-view");
  const $emptyState = document.getElementById("empty-state");
  const $lastScan = document.getElementById("last-scan");
  const $btnRefresh = document.getElementById("btn-refresh");
  const $scanDays = document.getElementById("scan-days");
  const $timeSegments = document.getElementById("time-segments");
  const $searchOverlay = document.getElementById("search-overlay");

