/* ===== App Layout (sidebar + chat panel) ===== */

.app-layout {
  display: flex;
  height: calc(100vh - 57px); /* viewport minus header */
  overflow: hidden;
}

/* ===== Sidebar ===== */

.sidebar {
  width: 340px;
  min-width: 240px;
  max-width: 50vw;
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  background: var(--bg-secondary);
  border-right: 1px solid var(--border);
  overflow: hidden;
  transition: width 200ms ease, min-width 200ms ease;
}

.sidebar.collapsed {
  width: 0;
  min-width: 0;
  border-right: none;
  overflow: hidden;
}

.sidebar-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 10px;
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
  gap: 6px;
}

.sidebar-toggle {
  width: 28px;
  height: 28px;
  border: 1px solid var(--border);
  border-radius: 4px;
  background: var(--bg-surface);
  color: var(--text-muted);
  cursor: pointer;
  font-size: 14px;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  transition: all 100ms ease;
}
.sidebar-toggle:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}
.sidebar.collapsed + .sidebar-resize-handle + .chat-panel .sidebar-toggle-restore {
  display: flex;
}

.sidebar-search {
  font-family: var(--font-mono);
  font-size: var(--font-size-sm);
  color: var(--text-muted);
  padding: 6px 10px;
  cursor: pointer;
  border-bottom: 1px solid var(--border-light);
  flex-shrink: 0;
  display: flex;
  align-items: center;
  gap: 6px;
}
.sidebar-search:hover {
  background: var(--bg-hover);
  color: var(--text-secondary);
}
.sidebar-search kbd {
  font-family: var(--font-mono);
  font-size: 10px;
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: 3px;
  padding: 1px 5px;
}

.sidebar-content {
  flex: 1;
  overflow-y: auto;
  padding: 8px;
}

/* Sidebar resize handle */
.sidebar-resize-handle {
  width: 4px;
  cursor: ew-resize;
  background: transparent;
  flex-shrink: 0;
  transition: background 100ms ease;
}
.sidebar-resize-handle:hover {
  background: var(--accent);
}

/* ===== Time Segments (inside sidebar header) ===== */

.time-segments {
  display: flex;
  border: 1px solid var(--border);
  border-radius: 6px;
  overflow: hidden;
  flex: 1;
}

