1759	  max-width: 300px;
1760	  max-height: 200px;
1761	  border-radius: 6px;
1762	  object-fit: contain;
1763	}
1764	
1765	/* Input bar */
1766	.chat-input-bar {
1767	  display: flex;
1768	  align-items: flex-end;
1769	  gap: 6px;
1770	  padding: 8px 10px;
1771	  background: var(--bg-secondary);
1772	  border-top: 1px solid var(--border);
1773	  flex-shrink: 0;
1774	}
1775	
