1831	  position: fixed;
1832	  bottom: 0;
1833	  left: 0;
1834	  right: 0;
1835	  display: flex;
1836	  align-items: center;
1837	  gap: 6px;
1838	  padding: 6px 12px;
1839	  background: var(--bg-secondary);
1840	  border-top: 1px solid var(--border);
