file.content:
/* ===== Chat Window Layer ===== */

.chat-window-layer {
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 100;
}

/* ===== Floating Chat Window ===== */

.chat-window {
  position: fixed;
  display: flex;
  flex-direction: column;
  background: var(--bg-primary);
  border: 1px solid var(--border);
  border-radius: 10px;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.15), 0 0 0 1px rgba(0, 0, 0, 0.05);
  overflow: hidden;
  pointer-events: auto;
  z-index: 101;
  min-width: 360px;
  min-height: 280px;
  transition: box-shadow 150ms ease;
}

.chat-window.focused {
  box-shadow: 0 12px 48px rgba(0, 0, 0, 0.25), 0 0 0 2px var(--accent);
}

.chat-window.maximized {
  top: 0 !important;
  left: 0 !important;
  right: 0 !important;
  bottom: 0 !important;
  width: 100vw !important;
  height: 100vh !important;
  border-radius: 0;
}

.chat-window.hidden {
  display: none;
}

/* Title bar */
.chat-window-titlebar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 6px 0 12px;
  height: 36px;
  background: var(--bg-secondary);
  border-bottom: 1px solid var(--border);
  cursor: grab;
  user-select: none;
  flex-shrink: 0;
}
.chat-window-titlebar:active { cursor: grabbing; }

.chat-window-title {
  font-family: var(--font-mono, monospace);
  font-size: 12px;
  font-weight: 600;
  color: var(--text-primary);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  flex: 1;
  min-width: 0;
}

.chat-window-controls {
  display: flex;
  align-items: center;
  gap: 2px;
  flex-shrink: 0;
}

.chat-window-btn {
  width: 28px;
  height: 28px;
  border: none;
  background: none;
  color: var(--text-muted);
  cursor: pointer;
  font-size: 14px;
  border-radius: 4px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 100ms ease;
}
.chat-window-btn:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.chat-window-cost {
  font-family: var(--font-mono, monospace);
  font-size: 10px;
  color: var(--text-muted);
  padding: 1px 6px;
  border: 1px solid var(--border);
  border-radius: 3px;
  white-space: nowrap;
  margin-right: 4px;
}
.chat-window-cost.hidden { display: none; }
.chat-window-cost.context-warn { color: #e5c07b; border-color: #e5c07b44; }
.chat-window-cost.context-critical { color: #e06c75; border-color: #e06c7544; }

/* Chat body: sidebar + messages side by side */
.chat-window-body {
  display: flex;
  flex: 1;
  overflow: hidden;
  min-height: 0;
}

/* Turn navigation sidebar */
.chat-turn-sidebar {
  width: 180px;
  flex-shrink: 0;
  border-right: 1px solid var(--border);
  background: var(--bg-secondary);
  display: flex;
  flex-direction: column;
  overflow: hidden;
}
.chat-turn-sidebar.hidden,
.chat-turn-sidebar.collapsed {
  display: none;
}

.turn-sidebar-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 6px 8px;
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}
.turn-sidebar-title {
  font-family: var(--font-heading, sans-serif);
  font-size: 10px;
  text-transform: uppercase;
  color: var(--text-muted);
  letter-spacing: 0.5px;
}
.turn-counter {
  font-family: var(--font-mono, monospace);
  font-size: 10px;
  color: var(--text-muted);
}

.turn-list {
  flex: 1;
  overflow-y: auto;
  padding: 4px 0;
}

.turn-item {
  display: flex;
  align-items: flex-start;
  gap: 6px;
  padding: 4px 8px;
  cursor: pointer;
  border-left: 2px solid transparent;
}
.turn-item:hover {
  background: var(--bg-hover);
}
.turn-item.active {
  border-left-color: var(--accent);
  background: var(--accent-dim);
}

.turn-label {
  font-family: var(--font-mono, monospace);
  font-size: 10px;
  color: var(--accent);
  min-width: 16px;
  flex-shrink: 0;
  font-weight: 700;
}

.turn-preview {
  font-size: 10px;
  font-weight: 400;
  color: var(--text-muted);
  line-height: 1.4;
  overflow: hidden;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
}

.turn-shortcuts {
  padding: 4px 8px;
  font-size: 9px;
  color: var(--text-muted);
  border-top: 1px solid var(--border);
  text-align: center;
  flex-shrink: 0;
}

/* Turn highlight flash when jumping */
.chat-bubble.user.turn-highlight {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
  transition: outline-color 1.5s ease-out;
}

/* Chat messages area */
.chat-window-messages {
  flex: 1;
  overflow-y: auto;
  padding: 16px;
  position: relative;
}

/* User bubble */
.chat-bubble.user {
  background: var(--accent, #FF4D00);
  color: #fff;
  padding: 10px 16px;
  border-radius: 16px 16px 4px 16px;
  margin: 12px 0 12px auto;
  max-width: 80%;
  width: fit-content;
  font-size: 14px;
  line-height: 1.5;
  word-wrap: break-word;
  white-space: pre-wrap;
  box-shadow: 0 1px 3px rgba(255, 77, 0, 0.2);
}

/* Assistant bubble */
.chat-bubble.assistant {
  background: var(--bg-surface, #222);
  color: var(--text-primary, #eee);
  padding: 14px 18px;
  border-radius: 16px 16px 16px 4px;
  margin: 12px auto 12px 0;
  max-width: 75%;
  width: fit-content;
  font-size: 14px;
  line-height: 1.6;
  border: 1px solid var(--border-light);
}

/* Markdown content inside assistant bubble */
.chat-md-content h1, .chat-md-content h2, .chat-md-content h3 {
  margin: 12px 0 6px;
  font-family: var(--font-heading, 'Archivo Black', sans-serif);
}
.chat-md-content h1 { font-size: 18px; }
.chat-md-content h2 { font-size: 16px; }
.chat-md-content h3 { font-size: 14px; }

.chat-md-content p { margin: 6px 0; }

.chat-md-content pre {
  background: var(--bg-code);
  border: 1px solid var(--border-code);
  border-radius: 6px;
  padding: 10px 12px;
  overflow-x: auto;
  font-size: 13px;
  margin: 8px 0;
}

.chat-md-content code {
  font-family: var(--font-mono, 'JetBrains Mono', monospace);
  font-size: 13px;
}

.chat-md-content :not(pre) > code {
  background: var(--bg-code-inline);
  padding: 1px 5px;
  border-radius: 3px;
}

.chat-md-content table {
  border-collapse: collapse;
  margin: 8px 0;
  font-size: 13px;
}
.chat-md-content th, .chat-md-content td {
  border: 1px solid var(--border-table);
  padding: 4px 10px;
  text-align: left;
}
.chat-md-content th { background: var(--bg-table-header); }

.chat-md-content ul, .chat-md-content ol {
  padding-left: 20px;
  margin: 6px 0;
}

.chat-md-content blockquote {
  border-left: 3px solid var(--accent, #FF4D00);
  margin: 8px 0;
  padding: 4px 12px;
  color: var(--text-secondary);
}

.chat-md-content a { color: var(--accent, #FF4D00); }

/* Thinking block */
.chat-thinking {
  margin: 6px 0;
  font-size: 13px;
  color: var(--text-muted);
  border-left: 2px solid var(--border);
  padding-left: 10px;
}
.chat-thinking summary {
  cursor: pointer;
  font-style: italic;
  color: var(--text-muted);
}
.chat-thinking-content {
  white-space: pre-wrap;
  font-family: var(--font-mono, monospace);
  font-size: 12px;
  margin-top: 4px;
  max-height: 200px;
  overflow-y: auto;
}

/* Tool call cards */
.chat-tool-card {
  margin: 6px 0;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--bg-surface);
  font-size: 13px;
  border-left: 3px solid var(--border);
  transition: border-color 150ms ease;
}

.chat-tool-card:has(.chat-tool-status.completed) {
  border-left-color: #48bb78;
}

.chat-tool-card:has(.chat-tool-status.in_progress) {
  border-left-color: var(--accent);
}

.chat-tool-card:has(.chat-tool-status.failed) {
  border-left-color: #e53e3e;
}

.chat-tool-header {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 6px 10px;
  cursor: pointer;
  list-style: none;
}
.chat-tool-header::-webkit-details-marker { display: none; }

.chat-tool-icon { font-size: 14px; }

.chat-tool-title {
  flex: 1;
  font-family: var(--font-mono, monospace);
  font-size: 12px;
  color: var(--text-primary);
}

.chat-tool-path {
  font-family: var(--font-mono, monospace);
  color: var(--text-muted);
  font-size: 11px;
}

.chat-tool-status {
  font-family: var(--font-mono, monospace);
  font-size: 11px;
  padding: 1px 6px;
  border-radius: 3px;
  text-transform: uppercase;
}
.chat-tool-status.pending { color: var(--text-muted); background: var(--bg-hover); }
.chat-tool-status.in_progress { color: var(--accent, #FF4D00); background: rgba(255,77,0,0.1); }
.chat-tool-status.completed { color: #4a4; background: rgba(68,170,68,0.1); }
.chat-tool-status.failed { color: #d44; background: rgba(221,68,68,0.1); }

/* Collapsed group of completed tool calls */
.chat-tool-group {
  margin: 6px 0;
  border: 1px solid var(--border);
  border-radius: 6px;
  background: var(--bg-surface);
  font-size: 13px;
}
.chat-tool-group > summary {
  padding: 6px 10px;
  cursor: pointer;
  font-family: var(--font-mono, monospace);
  font-size: 12px;
  color: var(--text-muted);
  list-style: none;
}
.chat-tool-group > summary::-webkit-details-marker { display: none; }

.chat-tool-body {
  padding: 0 10px 8px;
}

.chat-tool-output {
  background: var(--bg-code);
  border: 1px solid var(--border-code);
  border-radius: 4px;
  padding: 8px;
  font-family: var(--font-mono, monospace);
  font-size: 12px;
  white-space: pre-wrap;
  word-break: break-all;
  max-height: 300px;
  overflow-y: auto;
  color: var(--text-secondary);
  margin: 4px 0;
}

/* Diff display */
.chat-diff {
  margin: 4px 0;
}
.chat-diff-header {
  font-family: var(--font-mono, monospace);
  font-size: 11px;
  color: var(--text-muted);
  padding: 2px 0;
}
.chat-diff-content {
  background: var(--bg-code);
  border: 1px solid var(--border-code);
  border-radius: 4px;
  padding: 8px;
  font-family: var(--font-mono, monospace);
  font-size: 12px;
  white-space: pre-wrap;
  max-height: 300px;
  overflow-y: auto;
  color: var(--text-secondary);
}

/* Plan checklist */
.chat-plan {
  margin: 8px 0;
  padding: 8px 12px;
  background: var(--bg-hover);
  border-radius: 6px;
  border: 1px solid var(--border);
}
.chat-plan-title {
  font-family: var(--font-heading, sans-serif);
  font-size: 12px;
  text-transform: uppercase;
  color: var(--text-muted);
  margin-bottom: 4px;
}
.chat-plan ul {
  list-style: none;
  padding: 0;
  margin: 0;
}
.chat-plan-entry {
  padding: 2px 0;
  font-size: 13px;
  color: var(--text-secondary);
}
.chat-plan-entry.completed { color: #4a4; }
.chat-plan-entry.failed { color: #d44; }
.chat-plan-icon { margin-right: 6px; }

/* System messages */
.chat-system-msg {
  text-align: center;
  font-size: var(--font-size-sm);
  color: var(--text-muted);
  padding: 6px;
  font-family: var(--font-mono, monospace);
  font-style: italic;
}

.chat-terminated {
  color: #e06c75;
  border: 1px solid #e06c7533;
  border-radius: 4px;
  padding: 10px;
  margin: 8px 0;
}

/* Info banner */
.chat-info-banner {
  background: rgba(255,200,0,0.08);
  border: 1px solid rgba(255,200,0,0.2);
  border-radius: 6px;
  padding: 8px 12px;
  font-size: 13px;
  color: var(--text-secondary);
  margin: 8px 0;
}

/* Auth banner */
.chat-auth-banner {
  background: rgba(255,77,0,0.08);
  border: 1px solid rgba(255,77,0,0.2);
  border-radius: 6px;
  padding: 12px;
  margin: 8px 0;
  text-align: center;
}
.chat-auth-text {
  font-size: 13px;
  color: var(--accent);
  margin-bottom: 8px;
}
.chat-auth-retry {
  font-family: var(--font-mono, monospace);
  font-size: 12px;
  padding: 4px 16px;
  background: var(--accent, #FF4D00);
  color: #fff;
  border: none;
  border-radius: 4px;
  cursor: pointer;
}
.chat-auth-retry:hover { opacity: 0.8; }

/* Image preview strip above input */
.chat-image-preview {
  display: none;
  flex-shrink: 0;
  gap: 8px;
  padding: 6px 10px 0;
  background: var(--bg-secondary);
  border-top: 1px solid var(--border);
  overflow-x: auto;
}
.chat-image-preview.active {
  display: flex;
}
.image-preview-thumb {
  position: relative;
  flex-shrink: 0;
}
.image-preview-thumb img {
  height: 64px;
  max-width: 120px;
  object-fit: cover;
  border-radius: 4px;
  border: 1px solid var(--border);
}
.image-preview-remove {
  position: absolute;
  top: -4px;
  right: -4px;
  width: 18px;
  height: 18px;
  border-radius: 50%;
  border: none;
  background: var(--text-muted);
  color: var(--bg-primary);
  font-size: 12px;
  line-height: 1;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
}
.image-preview-remove:hover {
  background: var(--accent);
}

/* Images inside user bubbles */
.chat-bubble-images {
  display: flex;
  gap: 6px;
  flex-wrap: wrap;
  margin-bottom: 6px;
}
.chat-bubble-img {
  max-width: 300px;
  max-height: 200px;
  border-radius: 6px;
  object-fit: contain;
}

/* Input bar */
.chat-input-bar {
  display: flex;
  align-items: flex-end;
  gap: 6px;
  padding: 8px 10px;
  background: var(--bg-secondary);
  border-top: 1px solid var(--border);
  flex-shrink: 0;
}

.chat-input {
  flex: 1;
  background: var(--bg-surface);
  color: var(--text-primary);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 8px 12px;
  font-family: var(--font-body);
  font-size: 13px;
  resize: none;
  outline: none;
  max-height: 120px;
  line-height: 1.4;
}
.chat-input:focus { border-color: var(--accent); }
.chat-input:disabled { opacity: 0.5; }

.chat-send-btn {
  width: 32px;
  height: 32px;
  background: var(--accent);
  color: #fff;
  border: none;
  border-radius: 50%;
  font-size: 16px;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}
.chat-send-btn:hover { opacity: 0.8; }
.chat-send-btn:disabled { opacity: 0.3; cursor: default; }

.chat-stop-btn {
  width: 32px;
  height: 32px;
  background: #e53e3e;
  color: #fff;
  border: none;
  border-radius: 50%;
  font-size: 13px;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  transition: background 150ms ease;
}
.chat-stop-btn:hover { background: #c53030; }
.chat-stop-btn.hidden { display: none; }

/* ===== Chat Dock (minimized windows) ===== */

.chat-dock {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 6px 12px;
  background: var(--bg-secondary);
  border-top: 1px solid var(--border);
  z-index: 99;
  pointer-events: auto;
}

.chat-dock.hidden {
  display: none;
}

.chat-dock-pill {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 4px 12px;
  border: 1px solid var(--border);
  border-radius: 16px;
  background: var(--bg-surface);
  cursor: pointer;
  transition: all 150ms ease;
  max-width: 200px;
}
.chat-dock-pill:hover {
  border-color: var(--accent);
  background: var(--accent-dim);
}

.chat-dock-pill .dock-status {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--text-muted);
  flex-shrink: 0;
}
.chat-dock-pill.streaming .dock-status {
  background: var(--accent);
  animation: pulse-dot 2s ease-in-out infinite;
}

.chat-dock-pill .dock-title {
  font-family: var(--font-mono, monospace);
  font-size: 11px;
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.chat-dock-pill .dock-unread {
  font-family: var(--font-mono, monospace);
  font-size: 9px;
  font-weight: 700;
  min-width: 16px;
  height: 16px;
  line-height: 16px;
  text-align: center;
  background: var(--accent);
  color: #fff;
  border-radius: 8px;
  flex-shrink: 0;
}

.chat-dock-pill .dock-close {
  font-size: 12px;
  color: var(--text-muted);
  cursor: pointer;
  opacity: 0;
  transition: opacity 100ms ease;
  padding: 0 2px;
  background: none;
  border: none;
}
.chat-dock-pill:hover .dock-close { opacity: 1; }
.chat-dock-pill .dock-close:hover { color: var(--accent); }

/* Resize handles */
.chat-resize-handle {
  position: absolute;
  z-index: 2;
}
.chat-resize-handle.right {
  top: 0; right: -3px; bottom: 0; width: 6px;
  cursor: ew-resize;
}
.chat-resize-handle.bottom {
  left: 0; right: 0; bottom: -3px; height: 6px;
  cursor: ns-resize;
}
.chat-resize-handle.corner {
  right: -3px; bottom: -3px; width: 12px; height: 12px;
  cursor: nwse-resize;
}

