/* ===== Responsive ===== */

@media (max-width: 800px) {
  .header,
  .content {
    padding-left: 16px;
    padding-right: 16px;
  }

  .header-title {
    font-size: 20px;
  }

  .session-row {
    grid-template-columns: 10px 1fr auto;
    gap: 8px;
  }

  .status-label,
  .time-ago {
    display: none;
  }

  .chat-bubble.assistant {
    max-width: 90%;
  }

  /* On small screens, chat windows go full-screen */
  .chat-window {
    top: 0 !important;
    left: 0 !important;
    width: 100vw !important;
    height: 100vh !important;
    border-radius: 0;
    min-width: unset;
    min-height: unset;
  }

  .chat-turn-sidebar { display: none; }
}

/* ===== Dark Mode ===== */

/* ===== Dark Mode ===== */
/*
 * Theme is controlled by JS adding .dark to <html>.
 * JS sets .dark based on: localStorage preference, OS media query, or toggle.
 * Variables and component overrides both use the single .dark selector.
 */

html.dark {
  --bg-primary: #0e0e0e;
  --bg-secondary: #181818;
  --bg-hover: #222222;
  --bg-surface: #1e1e1e;

  --text-primary: #EEEEEE;
  --text-secondary: #BBBBBB;
  --text-muted: #777777;

  --border: #2e2e2e;
  --border-light: #252525;

  --accent-dim: rgba(255, 77, 0, 0.15);

  --bg-code: #0a0a0a;
  --border-code: #2e2e2e;
  --bg-code-inline: rgba(255, 255, 255, 0.08);
  --bg-table-header: rgba(255, 255, 255, 0.05);
  --border-table: #444444;

  --status-done: #888888;
  --status-likely-done: #666666;

  --badge-claude: #DDDDDD;
  --badge-codex: #AAAAAA;
}

html.dark .header { box-shadow: 0 1px 6px rgba(0, 0, 0, 0.3); border-bottom-color: #222; }

